import { useCallback } from 'react';

import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

export default function AccessRecordsPage() {
  const ownerLabelBuilder = useCallback((owner) => `${owner.parcel_code} - ${owner.full_name} (${owner.rut})`, []);
  const ownerOptions = useSelectOptions('/maps/parcel-options/', ownerLabelBuilder, { include_inactive: 'true' });

  const columns = [
    { key: 'owner_parcel_code', label: 'Parcela' },
    { key: 'owner_display', label: 'Propietario' },
    { key: 'full_name', label: 'Nombre completo' },
    { key: 'rut', label: 'RUT' },
    { key: 'plate', label: 'Patente' },
    { key: 'motive', label: 'Motivo' },
    { key: 'company_name', label: 'Empresa' },
    { key: 'access_datetime', label: 'Fecha/Hora' },
    {
      key: 'status',
      label: 'Estado',
      render: (row) => <Chip size="small" label={row.status} color={row.status === 'blocked' ? 'error' : 'success'} />
    }
  ];

  const fields = () => [
    { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: [{ value: '', label: 'Sin parcela' }, ...ownerOptions] },
    { name: 'full_name', label: 'Nombre completo', required: true },
    { name: 'rut', label: 'RUT' },
    { name: 'plate', label: 'Patente' },
    { name: 'motive', label: 'Motivo' },
    { name: 'company_name', label: 'Empresa' },
    { name: 'access_datetime', label: 'Fecha/Hora', type: 'datetime-local', required: true },
    { name: 'note', label: 'Nota', type: 'textarea', fullWidth: true },
    { name: 'card_number', label: 'Tarjeton numero' },
    { name: 'card_color', label: 'Tarjeton color' }
  ];

  const mapPayload = (values) => ({
    ...values,
    owner: values.owner || null
  });

  return (
    <CrudResourceModule
      title="Portales / Accesos"
      path="/access/access-records/"
      columns={columns}
      fields={fields}
      defaultOrdering="-access_datetime"
      mapPayload={mapPayload}
      searchPlaceholder="Buscar por nombre, RUT, patente o parcela (lote-numero)..."
      extraFilters={[
        {
          key: 'status',
          label: 'Estado',
          options: [
            { value: 'allowed', label: 'Permitido' },
            { value: 'blocked', label: 'Bloqueado' }
          ]
        }
      ]}
    />
  );
}

